const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  // ✅ Label function (safe + clean)
  const getAQILabel = (value) => {
    const v = Number(value);

    if (v === 1) return "Good";
    if (v === 2) return "Moderate";
    if (v === 3) return "Unhealthy (Sensitive)";
    if (v === 4) return "Unhealthy";
    if (v === 5) return "Very Unhealthy";
    if (v === 6) return "Hazardous";

    return "Unknown"; // fallback
  };

  // ✅ Color function (safe + correct)
  const getAQIColor = (value) => {
    const v = Number(value);

    if (v === 1) return "#00e400";
    if (v === 2) return "#ffff00";
    if (v === 3) return "#ff7e00";
    if (v === 4) return "#ff0000";
    if (v === 5) return "#8f3f97";
    if (v === 6) return "#7e0023";

    return "#ccc"; // fallback (if undefined/null)
  };

  return (
    <div className="card">
      <h2>{city}</h2>

      <img src={icon} alt="weather icon" />

      <p>{temperature}</p>
      <p>{feelsLike}</p>
      <p>{condition}</p>
      <p>{wind}</p>
      <p>{humidity}</p>

      {/* ✅ AQI BOX */}
      <div
        style={{
          backgroundColor: getAQIColor(aqi),
          padding: "10px",
          borderRadius: "8px",
          marginTop: "10px",
          color: "#000",
          fontWeight: "bold"
        }}
      >
        AQI: {aqi ?? "N/A"} {aqi ? `— ${getAQILabel(aqi)}` : ""}
      </div>
    </div>
  );
};

export default WeatherCard;
